import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../../../core/di/providers.dart';
import '../../../core/widgets/app_state.dart';
final dashboardProvider = FutureProvider<Map<String, dynamic>>((ref) => ref.read(apiProvider).get('/admin/dashboard'));
class AdminPage extends ConsumerWidget { const AdminPage({super.key}); @override Widget build(BuildContext context, WidgetRef ref) { final value = ref.watch(dashboardProvider); return Scaffold(appBar: AppBar(title: const Text('لوحة الإدارة')), body: value.when(loading: () => const Center(child: CircularProgressIndicator()), error: (_, __) => AppStateView(message: 'تعذر تحميل لوحة الإدارة', onRetry: () => ref.invalidate(dashboardProvider)), data: (data) { final items = <String, Object?>{'إجمالي المستخدمين': data['users'], 'المستخدمون النشطون': data['active_users'], 'الألعاب النشطة': data['active_games'], 'الألعاب المكتملة': data['completed_games'], 'طلبات الإيداع المعلقة': data['pending_deposits'], 'طلبات السحب المعلقة': data['pending_withdrawals'], 'القصص المنشورة': data['published_stories']}; return ListView(padding: const EdgeInsets.all(16), children: [Wrap(spacing: 10, runSpacing: 10, children: items.entries.map((item) => SizedBox(width: 170, child: Card(child: Padding(padding: const EdgeInsets.all(14), child: Column(crossAxisAlignment: CrossAxisAlignment.start, children: [Text(item.key), const SizedBox(height: 8), Text('${item.value}', style: Theme.of(context).textTheme.headlineSmall)])))).toList()), const SizedBox(height: 20), const Text('الإدارة التفصيلية متاحة عبر REST API المؤمّن: المستخدمون، القصص، طلبات المحفظة، والتدقيق.')]); })); }
}
